const slothbox = new Slothbox();
const result = await slothbox.catalog.resolveDockerHubImage({
  query: { image: 'postgres', tag: '16' },
});

const slothbox = new Slothbox();
const result = await slothbox.organizations.update({
  orgId: 'org_…',
  body: { name: 'checkout-dev' },
});

const slothbox = new Slothbox();
const result = await slothbox.members.setPermissions({
  orgId: 'org_…', userId: 'usr_…',
  body: { permissions: ['templates:write'] },
});

const slothbox = new Slothbox();
const result = await slothbox.members.setConnection({
  orgId: 'org_…', userId: 'usr_…', provider: 'github',
  body: { connectionId: 'conn_…' },
});

const slothbox = new Slothbox();
const result = await slothbox.invites.create({
  orgId: 'org_…',
  body: { email: 'dev@example.com' },
});

const slothbox = new Slothbox();
const result = await slothbox.templates.create({
  orgId: 'org_…',
  body: { name: 'checkout-stack', region: 'eu-west-2', services: [{ source: { kind: 'catalog', catalogKey: 'postgres' }, tag: '16' }], projects: [{ name: 'api', gitUrl: 'git@github.com:acme/checkout-api.git', runtime: 'node:22' }] },
});

const slothbox = new Slothbox();
const result = await slothbox.templates.replace({
  orgId: 'org_…', templateId: 'tmpl_…',
  body: { name: 'checkout-stack', region: 'eu-west-2', services: [{ source: { kind: 'catalog', catalogKey: 'postgres' }, tag: '16' }], projects: [{ name: 'api', gitUrl: 'git@github.com:acme/checkout-api.git', runtime: 'node:22' }] },
});

const slothbox = new Slothbox();
const box = await slothbox.environments.launch(
  { orgId: 'org_…', body: { templateId: 'tmpl_…' } },
  { idempotencyKey: 'launch-checkout-1' }, // retried launches with the same key return the original box
);

const slothbox = new Slothbox();
const result = await slothbox.environments.setAutoSleepPolicy({
  orgId: 'org_…',
  body: { idleAutoStop: { enabled: true, timeoutMinutes: 5 }, sleepSchedule: { enabled: true, timezone: 'Europe/London', windows: [{ days: [0], start: '20:00', end: '08:00' }] } },
});

const slothbox = new Slothbox();
const result = await slothbox.environments.setTemplateAutoSleep({
  orgId: 'org_…', templateId: 'tmpl_…',
  body: { autoSleep: {} },
});

const slothbox = new Slothbox();
const page = await slothbox.audit.listOrgEvents({ orgId: 'org_…' });
for await (const event of page) {
  console.log(event); // auto-fetches subsequent pages
}

const slothbox = new Slothbox();
const page = await slothbox.audit.listMyEvents();
for await (const event of page) {
  console.log(event); // auto-fetches subsequent pages
}

const slothbox = new Slothbox();
const page = await slothbox.audit.listApiKeyEvents({ keyId: 'key_…' });
for await (const event of page) {
  console.log(event); // auto-fetches subsequent pages
}

const slothbox = new Slothbox();
const result = await slothbox.awsConnections.create({
  orgId: 'org_…',
  body: { name: 'checkout-dev' },
});

const slothbox = new Slothbox();
const result = await slothbox.awsConnections.verify({
  orgId: 'org_…', connectionId: 'conn_…',
  body: { roleArn: 'arn:aws:iam::123456789012:role/slothbox-connection' },
});

const slothbox = new Slothbox();
const result = await slothbox.secrets.setConfig({
  orgId: 'org_…',
  body: { backend: 'ssm', connectionId: 'conn_…' },
});

const slothbox = new Slothbox();
const result = await slothbox.secrets.upsertEnvConfig({
  orgId: 'org_…', key: 'DATABASE_URL',
  body: { scope: 'org', kind: 'secret', value: '…' },
});

const slothbox = new Slothbox();
const result = await slothbox.secrets.deleteEnvConfig({
  orgId: 'org_…', key: 'DATABASE_URL',
  query: { scope: 'org', kind: 'secret' },
});

const slothbox = new Slothbox();
const result = await slothbox.registryCredentials.create({
  orgId: 'org_…',
  body: { type: 'token', label: '…', registry: 'ghcr.io', username: '…', secret: '…' },
});

const slothbox = new Slothbox();
const result = await slothbox.webhooks.createEndpoint({
  orgId: 'org_…',
  body: { url: 'https://example.com/hooks/slothbox', eventTypes: ['*'] },
});

const slothbox = new Slothbox();
const result = await slothbox.webhooks.updateEndpoint({
  orgId: 'org_…', endpointId: 'ep_…',
  body: { url: 'https://example.com/hooks/slothbox' },
});

const slothbox = new Slothbox();
const page = await slothbox.webhooks.listDeliveries({ orgId: 'org_…', endpointId: 'ep_…' });
for await (const delivery of page) {
  console.log(delivery); // auto-fetches subsequent pages
}

const slothbox = new Slothbox();
const result = await slothbox.webhooks.getDelivery({
  orgId: 'org_…', endpointId: 'ep_…', deliveryId: 'dlv_…',
});

const slothbox = new Slothbox();
const result = await slothbox.webhooks.redeliver({
  orgId: 'org_…', endpointId: 'ep_…', deliveryId: 'dlv_…',
});
